from synlte.object_history  l
inner join synlte.objecte_version r
on l.objectid = r.objectid
--and l.updatetime=r.updatetime


    l.objectname like concat('%',concat(#{searchText},'%'))



    and r.versions in (

        #{item}

    )



    and r.AUTHOR in(

        #{item}

    )




order by ${sort} ${sortOrder}

select distinct l.UPDATETIME, r.FIELDCHINESENAME,r.FIELDID,l.VERSION,l.VERSIONS,l.AUTHOR,l.MEMO
from synlte.synltefield_version l
inner join  synlte.synltefield_history r
on l.fiedid = r.fieldid
and l.updatetime = r.updatetime


        r.FIELDCHINESENAME like concat('%',concat(#{searchText},'%'))



        and l.versions in (

            #{item}

        )



        and l.AUTHOR in(

            #{item}

        )




    order by ${sort} ${sortOrder}

select l.dchinsename as dChineseName,l.determinerid,r.version,r.versions,r.updatetime,r.author,r.memo
from synlte.fielddeterminer_history  l
left join synlte.fielddeterminer_version  r
on l.dname = r.dname and r.updatetime= l.moddate


        l.dchinsename like concat('%',concat(#{searchText},'%'))



        and r.versions in (

            #{item}

        )



        and r.AUTHOR in(

            #{item}

        )




    order by ${sort} ${sortOrder}
